    58→// Project health dimensions for radar chart
    59→function buildHealthData(projects: AnyRow[], safety: AnyRow[], invoices: AnyRow[]) {
    60→  const active = projects.filter(p => p.status === 'active');
    61→  const avgProgress = active.length ? active.reduce((s, p) => s + Number(p.progress ?? 0), 0) / active.length : 0;
    62→  const budgetHealth = active.length ? active.reduce((s, p) => {
    63→    const burn = Number(p.spent ?? 0) / (Number(p.budget ?? 1) || 1);
    64→    return s + (1 - Math.abs(burn - Number(p.progress ?? 0) / 100));
    65→  }, 0) / active.length * 100 : 50;
    66→  const safetyScore = Math.max(0, 100 - safety.filter(s => ['open', 'investigating'].includes(String(s.status))).length * 15);
    67→  const rfiTurnaround = 70 - projects.length; // Simplified - would use actual RFI data
    68→  const cashHealth = invoices.length ? invoices.filter(i => i.status === 'paid').length / invoices.length * 100 : 50;
    69→  const compliance = 85; // Would be computed from RAMS expiry, training certs, etc.
    70→
    71→  return [
    72→    { dimension: 'Progress', score: Math.round(avgProgress), fullMark: 100 },
    73→    { dimension: 'Budget', score: Math.round(budgetHealth), fullMark: 100 },
    74→    { dimension: 'Safety', score: safetyScore, fullMark: 100 },
    75→    { dimension: 'RFIs', score: Math.max(0, rfiTurnaround), fullMark: 100 },
    76→    { dimension: 'Cash Flow', score: Math.round(cashHealth), fullMark: 100 },
    77→    { dimension: 'Compliance', score: compliance, fullMark: 100 },
    78→  ];
    79→}
